Change 1: Replace:
  # Group triples by subject while preserving order of appearance.
      subject_map: dict[str, list[Triple]] = {}
with:
  # Group triples by subject while preserving order of appearance.
      subject_map: dict[str, list[Triple]] = {}

      # Helper to build a short description for a subject using available templates.
      def _build_description(subj: str) -> str:
          """Return a comma‑separated string of relative clauses for *subj*."""
          desc_parts: list[str] = []
          for tt in subject_map.get(subj, []):
              if tt.predicate in rel_templates:
                  obj_val = tt.object.strip('"')
                  # avoid self‑reference loops
                  if obj_val == subj:
                      continue
                  desc_parts.append(rel_templates[tt.predicate].format(o=obj_val))
          return ", ".join(desc_parts)
